const body = $input.first().json.body || $input.first().json;
if (!body.engagement_id) return [{ json: { valid: false, error: 'engagement_id required' } }];
return [{ json: { valid: true, engagement_id: body.engagement_id, closed_by: body.closed_by || 'analyst', lessons_learned: body.lessons_learned || null } }];

const check = $input.first().json;
const warnings = [];
if (parseInt(check.open_criticals||0) > 0) warnings.push(`${check.open_criticals} open critical finding(s) — recommend remediation before close`);
if (parseInt(check.open_highs||0) > 0) warnings.push(`${check.open_highs} open high finding(s)`);
if (parseInt(check.pending_validation||0) > 0) warnings.push(`${check.pending_validation} finding(s) still pending analyst validation`);
return [{ json: {
  ...check,
  warnings,
  can_close: check.status === 'active',
  engagement_id: $('Validate Input').first().json.engagement_id
} }];
